import './App.css';

function App() {
  const [age,setAge]=useState
  return (
    <div className="App">
      <div className='form'>


        <h2>Request loan for <span>HSBC</span> bank</h2>

        <input type='text' placeholder='Enter Your Name'></input><br/>

        <input type='text' placeholder='Enter Your Phone Number'></input><br/>

        <input type='text' placeholder='Enter Your Age'></input><br/>

      <div className='check'>
        <input type='checkbox'/>
        <label> Aye You have employee?</label>
      </div>

        <select>
          <option>Less than 15,000k</option>
          <option>15,000 to 35,000k</option>
          <option>More than 35,000k</option>
        </select><br/>

        <button type='submit'>Submit</button>


      </div>
            </div>

  );
}

export default App;
